function icon(name, size, color) {
  size = size || 16;
  color = color || 'currentColor';
  const d = ICON_PATHS[name];
  if (!d) return '';
  return '<svg class="gi" width="' + size + '" height="' + size + '" viewBox="0 0 512 512" fill="' + color + '"><path d="' + d + '"/></svg>';
}
